INSERT INTO position_categories (id, positionId, name) VALUES (46, 4, 'Ticari Bakış');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (161, 46, '25', 'Yaptığı işin sonuçlarının kurumun beklediği ticari sonuçlar ile paralel olmasını gözetir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (162, 46, '26', 'Uygun durumlarda, satış fırsatlarını geliştirecek alternatif yaklaşımlar tavsiye eder.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (163, 46, '27', 'Kurumun müşteri sayısını geliştirmeye yönelik çalışmalarda bulunur.');
INSERT INTO position_categories (id, positionId, name) VALUES (47, 4, 'Planlama ve Organize Etme');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (164, 47, '28', 'Görevlerini sahip olduğu zamanı dikkate alarak gereken sürede tamamlar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (165, 47, '29', 'Birden fazla işe odaklanarak bunları eş zamanlı yürütebilir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (166, 47, '30', 'Planlama ile ilgili öncelikleri saptar, yetki sınırları içinde doğru sıralamayı gerçekleştirir.');
INSERT INTO position_categories (id, positionId, name) VALUES (48, 4, 'İş Disiplini ve Tutum');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (167, 48, '1', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (168, 48, '2', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (169, 48, '3', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (170, 48, '4', 'İnsan Kaynakları tarafından yayınlanan Şirket Davranış Talimatına uygun hareket eder.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (171, 48, '5', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (49, 4, 'Kasa');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (172, 49, '20', 'Yöneticisinin verdiği talimatlara uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (50, 4, 'İlgili / Restoran Yöneticisi');
INSERT INTO position_categories (id, positionId, name) VALUES (51, 5, 'Görevi');
INSERT INTO position_categories (id, positionId, name) VALUES (52, 5, 'Görev Bilinci');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (173, 52, '1', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (174, 52, '2', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (175, 52, '3', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (176, 52, '4', 'Ahlaki ve etik değerlere uygun davranır. Davranışlarının sorumluluğunu üstlenir.');
INSERT INTO position_categories (id, positionId, name) VALUES (53, 5, 'İletişim Becerisi');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (177, 53, '5', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (178, 53, '6', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır.');
INSERT INTO position_questions (id, categoryId, questionNumber, questionText) VALUES (179, 53, '7', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');

